#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Node structure definition
struct Node {
 int data;
 struct Node* next;
};

// Create a new node
struct Node* createNode(int data) {
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = data;
 newNode->next = NULL;
 return newNode;
}

// Display linked list
void displayList(struct Node* head) {
 struct Node* temp = head;
 while (temp != NULL) {
 printf("%d", temp->data);
 if (temp->next != NULL) printf(" → ");
 temp = temp->next;
 }
 printf(" → NULL\n");
}

// Concatenate two linked lists
struct Node* concatenate(struct Node* list1, struct Node* list2) {
 if (list1 == NULL) return list2;
 if (list2 == NULL) return list1;

 struct Node* temp = list1;
 while (temp->next != NULL) {
 temp = temp->next;
 }
 temp->next = list2;
 return list1;
}

// Reverse linked list in-place
struct Node* reverseList(struct Node* head) {
 struct Node* prev = NULL;
 struct Node* current = head;
 struct Node* next = NULL;

 while (current != NULL) {
 next = current->next;
 current->next = prev;
 prev = current;
 current = next;
 }
 return prev;
}

// Detect cycle using Floyd's algorithm
bool hasCycle(struct Node* head) {
 if (head == NULL) return false;

 struct Node* slow = head;
 struct Node* fast = head;

 while (fast != NULL && fast->next != NULL) {
 slow = slow->next;
 fast = fast->next->next;

 if (slow == fast) {
 return true;
 }
 }
 return false;
}

// Find middle element using two-pointer technique
struct Node* findMiddle(struct Node* head) {
 if (head == NULL) return NULL;

 struct Node* slow = head;
 struct Node* fast = head;

 while (fast != NULL && fast->next != NULL) {
 slow = slow->next;
 fast = fast->next->next;
 }
 return slow;
}

// Merge two sorted linked lists
struct Node* mergeSortedLists(struct Node* list1, struct Node* list2) {
 struct Node dummy;
 dummy.next = NULL;
 struct Node* tail = &dummy;

 while (list1 != NULL && list2 != NULL) {
 if (list1->data <= list2->data) {
 tail->next = list1;
 list1 = list1->next;
 } else {
 tail->next = list2;
 list2 = list2->next;
 }
 tail = tail->next;
 }

 if (list1 != NULL) tail->next = list1;
 if (list2 != NULL) tail->next = list2;

 return dummy.next;
}

// Find middle for merge sort
struct Node* findMiddleForSplit(struct Node* head) {
 struct Node* slow = head;
 struct Node* fast = head->next;

 while (fast != NULL && fast->next != NULL) {
 slow = slow->next;
 fast = fast->next->next;
 }
 return slow;
}

// Merge sort for linked list
struct Node* mergeSort(struct Node* head) {
 if (head == NULL || head->next == NULL) {
 return head;
 }

 struct Node* middle = findMiddleForSplit(head);
 struct Node* nextOfMiddle = middle->next;
 middle->next = NULL;

 struct Node* left = mergeSort(head);
 struct Node* right = mergeSort(nextOfMiddle);

 return mergeSortedLists(left, right);
}

