class Node<T> {
 T data;
 Node<T> next;

 public Node(T data) {
 this.data = data;
 this.next = null;
 }
}

class LinkedList<T extends Comparable<T>> {
 private Node<T> head;
 private int size;

 public LinkedList() {
 this.head = null;
 this.size = 0;
 }

 public void append(T data) {
 Node<T> newNode = new Node<>(data);
 if (head == null) {
 head = newNode;
 } else {
 Node<T> current = head;
 while (current.next != null) {
 current = current.next;
 }
 current.next = newNode;
 }
 size++;
 }

 public Node<T> getHead() {
 return head;
 }

 public void setHead(Node<T> head) {
 this.head = head;
 }

 public void display() {
 Node<T> current = head;
 while (current != null) {
 System.out.print(current.data);
 if (current.next != null) System.out.print(" → ");
 current = current.next;
 }
 System.out.println(" → NULL");
 }

 // Concatenate two linked lists
 public static <T> Node<T> concatenate(Node<T> list1, Node<T> list2) {
 if (list1 == null) return list2;
 if (list2 == null) return list1;

 Node<T> current = list1;
 while (current.next != null) {
 current = current.next;
 }
 current.next = list2;
 return list1;
 }

 // Reverse linked list in-place
 public static <T> Node<T> reverseList(Node<T> head) {
 Node<T> prev = null;
 Node<T> current = head;

 while (current != null) {
 Node<T> next = current.next;
 current.next = prev;
 prev = current;
 current = next;
 }
 return prev;
 }

 // Detect cycle using Floyd's algorithm
 public static <T> boolean hasCycle(Node<T> head) {
 if (head == null) return false;

 Node<T> slow = head;
 Node<T> fast = head;

 while (fast != null && fast.next != null) {
 slow = slow.next;
 fast = fast.next.next;

 if (slow == fast) {
 return true;
 }
 }
 return false;
 }

 // Find middle element using two-pointer technique
 public static <T> Node<T> findMiddle(Node<T> head) {
 if (head == null) return null;

 Node<T> slow = head;
 Node<T> fast = head;

 while (fast != null && fast.next != null) {
 slow = slow.next;
 fast = fast.next.next;
 }
 return slow;
 }

 // Merge two sorted linked lists
 public static <T extends Comparable<T>> Node<T> mergeSortedLists(Node<T> list1, Node<T> list2) {
 Node<T> dummy = new Node<>(null);
 Node<T> tail = dummy;

 while (list1 != null && list2 != null) {
 if (list1.data.compareTo(list2.data) <= 0) {
 tail.next = list1;
 list1 = list1.next;
 } else {
 tail.next = list2;
 list2 = list2.next;
 }
 tail = tail.next;
 }

 if (list1 != null) tail.next = list1;
 if (list2 != null) tail.next = list2;

 return dummy.next;
 }

 // Find middle for merge sort split
 private static <T> Node<T> findMiddleForSplit(Node<T> head) {
 Node<T> slow = head;
 Node<T> fast = head.next;

 while (fast != null && fast.next != null) {
 slow = slow.next;
 fast = fast.next.next;
 }
 return slow;
 }

 // Merge sort for linked list
 public static <T extends Comparable<T>> Node<T> mergeSort(Node<T> head) {
 if (head == null || head.next == null) {
 return head;
 }

 Node<T> middle = findMiddleForSplit(head);
 Node<T> nextOfMiddle = middle.next;
 middle.next = null;

 Node<T> left = mergeSort(head);
 Node<T> right = mergeSort(nextOfMiddle);

 return mergeSortedLists(left, right);
 }
}

public class AdvancedListOperations {
 public static void main(String[] args) {
 // Test Concatenation
 LinkedList<Integer> list1 = new LinkedList<>();
 LinkedList<Integer> list2 = new LinkedList<>();

 for (int i = 1; i <= 3; i++) list1.append(i);
 for (int i = 4; i <= 6; i++) list2.append(i);

 System.out.print("List 1: ");
 list1.display();
 System.out.print("List 2: ");
 list2.display();

 Node<Integer> concatenated = LinkedList.concatenate(list1.getHead(), list2.getHead());
 LinkedList<Integer> concList = new LinkedList<>();
 concList.setHead(concatenated);
 System.out.print("After concatenation: ");
 concList.display();

 // Test Reversal
 Node<Integer> reversed = LinkedList.reverseList(concatenated);
 LinkedList<Integer> revList = new LinkedList<>();
 revList.setHead(reversed);
 System.out.print("After reversal: ");
 revList.display();

 // Test Find Middle
 LinkedList<Integer> testList = new LinkedList<>();
 for (int i = 10; i <= 50; i += 10) testList.append(i);
 Node<Integer> middle = LinkedList.findMiddle(testList.getHead());
 System.out.println("Middle element: " + middle.data);

 // Test Merge Sorted Lists
 LinkedList<Integer> sorted1 = new LinkedList<>();
 LinkedList<Integer> sorted2 = new LinkedList<>();

 sorted1.append(1); sorted1.append(3); sorted1.append(5);
 sorted2.append(2); sorted2.append(4); sorted2.append(6);

 Node<Integer> merged = LinkedList.mergeSortedLists(sorted1.getHead(), sorted2.getHead());
 LinkedList<Integer> mergedList = new LinkedList<>();
 mergedList.setHead(merged);
 System.out.print("Merged sorted list: ");
 mergedList.display();

 // Test Cycle Detection
 Node<Integer> cycleTest = new Node<>(1);
 cycleTest.next = new Node<>(2);
 cycleTest.next.next = new Node<>(3);
 cycleTest.next.next.next = cycleTest.next; // Creates cycle

 System.out.println("Cycle detected: " + LinkedList.hasCycle(cycleTest));

 // Test Merge Sort
 LinkedList<Integer> unsorted = new LinkedList<>();
 unsorted.append(64); unsorted.append(34); unsorted.append(25);
 unsorted.append(12); unsorted.append(22);

 System.out.print("Before merge sort: ");
 unsorted.display();

 Node<Integer> sorted = LinkedList.mergeSort(unsorted.getHead());
 LinkedList<Integer> sortedList = new LinkedList<>();
 sortedList.setHead(sorted);
 System.out.print("After merge sort: ");
 sortedList.display();
 }
}
